/** Auto-generated from public/index.html — run: node scripts/embed.js */
module.exports = "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>QR Magic（個人用）</title>\n  <script src=\"https://cdnjs.cloudflare.com/ajax/libs/Sortable/1.15.2/Sortable.min.js\"></script>\n  <script src=\"https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js\"></script>\n  <style>\n    :root { font-family: system-ui, sans-serif; color: #111; background: #f4f4f5; }\n    body { margin: 0 auto; max-width: 520px; padding: 1rem 1rem 3rem; }\n    h1 { font-size: 1.15rem; margin: 0 0 0.75rem; }\n    h2 { font-size: 0.95rem; margin: 1.25rem 0 0.5rem; }\n    input[type=\"text\"], input[type=\"password\"], textarea {\n      width: 100%; box-sizing: border-box; padding: 0.5rem; font-size: 1rem; border: 1px solid #ccc; border-radius: 6px;\n    }\n    textarea { min-height: 2.5rem; resize: vertical; }\n    button {\n      cursor: pointer; border: none; border-radius: 8px; padding: 0.65rem 1rem; font-size: 0.95rem; font-weight: 600;\n    }\n    .btn-primary { background: #2563eb; color: #fff; }\n    .btn-secondary { background: #e4e4e7; color: #18181b; }\n    .btn-danger { background: #dc2626; color: #fff; }\n    .btn-warn { background: #ea580c; color: #fff; }\n    .row { display: flex; gap: 0.35rem; align-items: center; margin-bottom: 0.4rem; background: #fff; padding: 0.35rem; border-radius: 8px; border: 1px solid #e4e4e7; }\n    .handle { cursor: grab; user-select: none; padding: 0 0.35rem; color: #71717a; font-size: 1.1rem; }\n    .row input { flex: 1; }\n    .check { font-size: 0.8rem; padding: 0.35rem 0.5rem; background: #eef2ff; color: #3730a3; border-radius: 6px; white-space: nowrap; }\n    .panel { background: #fff; border-radius: 10px; padding: 0.85rem; border: 1px solid #e4e4e7; margin-top: 0.75rem; }\n    #qr { display: flex; justify-content: center; margin-top: 0.5rem; }\n    #perf { display: none; position: fixed; inset: 0; background: rgba(0,0,0,.55); align-items: center; justify-content: center; z-index: 50; }\n    #perf .box { background: #fff; padding: 1.25rem; border-radius: 12px; max-width: 90%; }\n    .muted { color: #71717a; font-size: 0.85rem; word-break: break-all; }\n    .toolbar { display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 0.5rem; }\n    #cardModal { display: none; position: fixed; inset: 0; background: rgba(0,0,0,.5); z-index: 60; align-items: flex-end; justify-content: center; }\n    #cardModal .sheet { background: #fff; width: 100%; max-width: 520px; border-radius: 12px 12px 0 0; padding: 0.75rem; max-height: 85vh; overflow: auto; }\n    .grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 0.35rem; }\n    .grid div { text-align: center; padding: 0.45rem; border-radius: 8px; background: #f4f4f5; border: 1px solid #d4d4d8; cursor: pointer; font-size: 0.9rem; }\n    .grid div:active { transform: scale(0.98); }\n    .info { font-size: 0.8rem; color: #52525b; margin-top: 0.35rem; }\n  </style>\n</head>\n<body>\n  <h1>QR Magic（個人用）</h1>\n  <p class=\"muted\">アカウントはありません。<code>ADMIN_TOKEN</code> を知っている人だけが設定できます。観客用URLは下に表示されます。</p>\n\n  <div id=\"gate\" class=\"panel\">\n    <h2>管理用トークン</h2>\n    <p class=\"muted\">サーバーの環境変数 <code>ADMIN_TOKEN</code> と同じ文字列を入力してください。</p>\n    <input type=\"password\" id=\"gateToken\" placeholder=\"ADMIN_TOKEN\" autocomplete=\"off\" />\n    <div class=\"toolbar\" style=\"margin-top:0.65rem\">\n      <button type=\"button\" class=\"btn-primary\" id=\"gateBtn\">開く</button>\n    </div>\n  </div>\n\n  <div id=\"app\" style=\"display:none\">\n    <div class=\"panel\">\n      <h2>観客用QR（このURLをQR化）</h2>\n      <p class=\"muted\" style=\"font-size:.82rem\">インターネット用は <code>npm.cmd run public</code> で起動すると自動で入ります。手動なら .env の <code>PUBLIC_BASE_URL</code> でも可。</p>\n      <p id=\"publicUrl\" class=\"muted\"></p>\n      <div id=\"qr\"></div>\n    </div>\n\n    <div class=\"panel\">\n      <h2>リダイレクトURLのテンプレート</h2>\n      <p class=\"muted\">必ず <code>{query}</code> を含めてください。任意で <code>{host}</code>。</p>\n      <textarea id=\"template\"></textarea>\n    </div>\n\n    <div class=\"panel\">\n      <h2>キーワード（ドラッグの≡で並べ替え）</h2>\n      <div id=\"rows\"></div>\n      <div class=\"toolbar\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"addRow\">行を追加</button>\n        <button type=\"button\" class=\"btn-primary\" id=\"saveBtn\">設定を保存</button>\n        <button type=\"button\" class=\"btn-secondary\" id=\"resetCounter\">カウンタだけ0に</button>\n      </div>\n    </div>\n\n    <div class=\"panel\">\n      <h2>現在の状態</h2>\n      <p id=\"statusLine\" class=\"muted\"></p>\n      <ul id=\"preview\"></ul>\n    </div>\n\n    <div class=\"toolbar\">\n      <button type=\"button\" class=\"btn-warn\" id=\"btnPerform\">パフォーマンス</button>\n      <button type=\"button\" class=\"btn-warn\" id=\"btnPermanent\">永続化パフォーマンス</button>\n    </div>\n    <p class=\"info\">通常: 終了後カウンタ0に。永続化: 終了後もカウンタ維持（使い回しはしにくくなります）。</p>\n\n    <div class=\"panel\">\n      <h2>名刺用QR（1枚＝1URL・初回で単語固定）</h2>\n      <p class=\"muted\">先に<strong>URLだけ</strong>をたくさん作り、名刺に<strong>それぞれ違うQR</strong>を印刷しておきます。<strong>パフォーマンスは不要</strong>です。</p>\n      <p class=\"muted\">本番でマジシャンがスマホに<strong>そのときの単語</strong>（例：りんご）を入れて保存したうえで、観客がその名刺のQRを<strong>初めて</strong>読むと、その単語に<strong>ずっと</strong>固定されます（家に帰ってから読んでも同じ検索結果）。名刺ごとに別の単語にしたいときは、読ませるタイミングでキーワードを変えてください。</p>\n      <p class=\"muted\">飛び先は「リダイレクトURLのテンプレート」を使います（あとからテンプレだけ変えれば、固定された単語の行き先を変えられます）。1回あたり最大5000枚。</p>\n      <p id=\"ticketStatus\" class=\"muted\"></p>\n      <label class=\"muted\">枚数</label>\n      <input type=\"number\" id=\"ticketCount\" value=\"10\" min=\"1\" max=\"5000\" style=\"width:6rem;margin-left:.35rem\" />\n      <div class=\"toolbar\" style=\"margin-top:0.5rem\">\n        <button type=\"button\" class=\"btn-primary\" id=\"btnIssueTickets\">名刺用URLを発行</button>\n        <button type=\"button\" class=\"btn-danger\" id=\"btnClearTickets\">名刺用を全削除</button>\n      </div>\n      <label class=\"muted\" style=\"display:block;margin-top:0.65rem\">発行されたURL（1行1本・QRにしてください）</label>\n      <textarea id=\"ticketUrls\" readonly rows=\"10\" style=\"width:100%;font-size:.72rem;font-family:ui-monospace,monospace\"></textarea>\n    </div>\n  </div>\n\n  <div id=\"perf\">\n    <div class=\"box\">\n      <strong>パフォーマンス中</strong>\n      <p id=\"perfText\" class=\"muted\" style=\"margin:0.75rem 0\"></p>\n      <button type=\"button\" class=\"btn-primary\" id=\"btnFinish\">終了</button>\n    </div>\n  </div>\n\n  <div id=\"cardModal\">\n    <div class=\"sheet\">\n      <p style=\"margin:0 0 0.5rem\"><strong>カード</strong> <span id=\"cardInfo\" class=\"muted\"></span></p>\n      <div class=\"grid\" id=\"marks\" style=\"margin-bottom:0.5rem\">\n        <div data-m=\"S\">♠</div><div data-m=\"D\">♦</div><div data-m=\"C\">♣</div><div data-m=\"H\">♥</div>\n      </div>\n      <div class=\"grid\" id=\"nums\" style=\"grid-template-columns:repeat(5,1fr);margin-bottom:0.5rem\"></div>\n      <div class=\"grid\" id=\"orders\" style=\"grid-template-columns:repeat(5,1fr);margin-bottom:0.5rem\"></div>\n      <div class=\"toolbar\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"cardClose\">閉じる</button>\n        <button type=\"button\" class=\"btn-danger\" id=\"cardClear\">この行を空に</button>\n      </div>\n      <p class=\"info\">スート・数字・順を選ぶと <code>S5/3</code> の形式で入ります。Joはジョーカー。</p>\n    </div>\n  </div>\n\n  <p id=\"toast\" style=\"display:none;position:fixed;bottom:1rem;left:50%;transform:translateX(-50%);background:#111;color:#fff;padding:.6rem 1rem;border-radius:8px;z-index:100\"></p>\n\n  <script>\n    const LS = \"qr_magic_admin_token\";\n    const gate = document.getElementById(\"gate\");\n    const appEl = document.getElementById(\"app\");\n\n    let adminToken = localStorage.getItem(LS) || \"\";\n    let state = null;\n    let publicPath = \"\";\n    /** サーバー .env の PUBLIC_BASE_URL（https の観客用オリジン） */\n    let publicBaseUrl = \"\";\n    let sortable = null;\n    let cardRow = -1;\n    let pick = { m: \"\", n: \"\", o: \"\" };\n\n    function toast(msg) {\n      const t = document.getElementById(\"toast\");\n      t.textContent = msg;\n      t.style.display = \"block\";\n      setTimeout(() => { t.style.display = \"none\"; }, 2200);\n    }\n\n    function authHeaders() {\n      return { Authorization: \"Bearer \" + adminToken, \"Content-Type\": \"application/json\" };\n    }\n\n    async function api(path, opt = {}) {\n      const r = await fetch(path, { ...opt, headers: { ...authHeaders(), ...opt.headers } });\n      if (r.status === 401) {\n        localStorage.removeItem(LS);\n        location.reload();\n        throw new Error(\"unauthorized\");\n      }\n      const j = await r.json().catch(() => ({}));\n      if (!r.ok) throw new Error(j.message || r.statusText);\n      return j;\n    }\n\n    function audienceOrigin() {\n      return (publicBaseUrl && publicBaseUrl.length > 0 ? publicBaseUrl : location.origin).replace(/\\/+$/, \"\");\n    }\n\n    function buildUrl(template, query) {\n      const host = audienceOrigin();\n      return template.replaceAll(\"{host}\", host).replaceAll(\"{query}\", encodeURIComponent(query));\n    }\n\n    function renderRows() {\n      const wrap = document.getElementById(\"rows\");\n      wrap.innerHTML = \"\";\n      (state.queries || []).forEach((q, i) => {\n        const row = document.createElement(\"div\");\n        row.className = \"row\";\n        row.dataset.index = String(i);\n        row.innerHTML =\n          '<span class=\"handle\" title=\"並べ替え\">≡</span>' +\n          '<input type=\"text\" value=\"' + escapeAttr(q) + '\" data-i=\"' + i + '\" />' +\n          '<button type=\"button\" class=\"check\" data-check=\"' + i + '\">CHECK</button>' +\n          '<button type=\"button\" class=\"btn-secondary\" style=\"padding:.35rem .5rem;font-size:.8rem\" data-card=\"' + i + '\">カード</button>' +\n          '<button type=\"button\" class=\"btn-danger\" style=\"padding:.35rem .5rem;font-size:.8rem\" data-del=\"' + i + '\">削除</button>';\n        wrap.appendChild(row);\n      });\n      wrap.querySelectorAll(\"input[type=text]\").forEach((inp) => {\n        inp.addEventListener(\"input\", () => {\n          const i = +inp.dataset.i;\n          state.queries[i] = inp.value;\n        });\n      });\n      wrap.querySelectorAll(\"[data-check]\").forEach((b) => {\n        b.addEventListener(\"click\", () => {\n          const i = +b.getAttribute(\"data-check\");\n          const q = (state.queries[i] || \"\").trim();\n          if (!q) return toast(\"キーワードが空です\");\n          window.open(buildUrl(state.serviceTemplate, q), \"_blank\");\n        });\n      });\n      wrap.querySelectorAll(\"[data-card]\").forEach((b) => {\n        b.addEventListener(\"click\", () => openCard(+b.getAttribute(\"data-card\")));\n      });\n      wrap.querySelectorAll(\"[data-del]\").forEach((b) => {\n        b.addEventListener(\"click\", () => {\n          const i = +b.getAttribute(\"data-del\");\n          state.queries.splice(i, 1);\n          renderRows();\n        });\n      });\n      if (sortable) sortable.destroy();\n      sortable = new Sortable(wrap, {\n        handle: \".handle\",\n        animation: 150,\n        onEnd() {\n          const inputs = [...wrap.querySelectorAll(\"input[type=text]\")];\n          state.queries = inputs.map((inp) => inp.value);\n          renderRows();\n        },\n      });\n    }\n\n    function escapeAttr(s) {\n      return String(s).replace(/&/g, \"&amp;\").replace(/\"/g, \"&quot;\").replace(/</g, \"&lt;\");\n    }\n\n    function renderQr(url) {\n      const el = document.getElementById(\"qr\");\n      el.innerHTML = \"\";\n      if (typeof QRCode !== \"undefined\") new QRCode(el, { text: url, width: 200, height: 200 });\n    }\n\n    function renderAll() {\n      document.getElementById(\"template\").value = state.serviceTemplate || \"\";\n      document.getElementById(\"statusLine\").textContent =\n        \"カウンタ: \" + state.counter +\n        \" / パフォーマンス: \" + (state.performanceActive ? \"ON\" : \"OFF\") +\n        (state.permanent ? \"（永続モード）\" : \"\") +\n        \" / 名刺用URL数: \" + (state.ticketCount != null ? state.ticketCount : 0);\n      document.getElementById(\"ticketStatus\").textContent =\n        \"登録中の名刺用URL: \" + (state.ticketCount != null ? state.ticketCount : 0) + \" 本\";\n      const ul = document.getElementById(\"preview\");\n      ul.innerHTML = \"\";\n      (state.queries || []).forEach((q, k) => {\n        const li = document.createElement(\"li\");\n        li.textContent = (k + 1) + \". \" + (q || \"（空）\");\n        ul.appendChild(li);\n      });\n      renderRows();\n      const full = audienceOrigin() + publicPath;\n      document.getElementById(\"publicUrl\").textContent = full;\n      renderQr(full);\n      document.getElementById(\"perf\").style.display = state.performanceActive ? \"flex\" : \"none\";\n      document.getElementById(\"perfText\").textContent = state.permanent\n        ? \"永続化モード: 終了後もカウンタは維持されます。\"\n        : \"通常モード: 終了するとカウンタは0に戻ります。\";\n    }\n\n    async function load() {\n      const data = await api(\"/api/state\");\n      publicPath = data.publicPath || \"\";\n      publicBaseUrl = typeof data.publicBaseUrl === \"string\" ? data.publicBaseUrl.trim() : \"\";\n      state = data.state;\n      renderAll();\n    }\n\n    async function save() {\n      state.serviceTemplate = document.getElementById(\"template\").value.trim();\n      if (!state.serviceTemplate.includes(\"{query}\")) {\n        toast(\"{query} を含めてください\");\n        return;\n      }\n      const data = await api(\"/api/state\", { method: \"PUT\", body: JSON.stringify({ queries: state.queries, serviceTemplate: state.serviceTemplate }) });\n      state = data.state;\n      toast(\"保存しました\");\n      renderAll();\n    }\n\n    function openCard(row) {\n      cardRow = row;\n      pick = { m: \"\", n: \"\", o: \"\" };\n      document.getElementById(\"cardModal\").style.display = \"flex\";\n      syncCardInfo();\n      const nums = document.getElementById(\"nums\");\n      nums.innerHTML = \"\";\n      for (let i = 1; i <= 13; i++) {\n        const d = document.createElement(\"div\");\n        d.textContent = String(i);\n        d.addEventListener(\"click\", () => { pick.n = String(i); tryCommitCard(); syncCardInfo(); });\n        nums.appendChild(d);\n      }\n      const jo = document.createElement(\"div\");\n      jo.textContent = \"Jo\";\n      jo.style.gridColumn = \"span 2\";\n      jo.addEventListener(\"click\", () => { pick.n = \"Jo\"; pick.m = \"\"; tryCommitCard(); syncCardInfo(); });\n      nums.appendChild(jo);\n      const orders = document.getElementById(\"orders\");\n      orders.innerHTML = \"\";\n      for (let i = 1; i <= 10; i++) {\n        const d = document.createElement(\"div\");\n        d.textContent = String(i);\n        d.addEventListener(\"click\", () => { pick.o = String(i); tryCommitCard(); syncCardInfo(); });\n        orders.appendChild(d);\n      }\n      document.querySelectorAll(\"#marks div\").forEach((d) => {\n        d.onclick = () => { pick.m = d.getAttribute(\"data-m\"); tryCommitCard(); syncCardInfo(); };\n      });\n    }\n\n    function syncCardInfo() {\n      document.getElementById(\"cardInfo\").textContent = \" M:\" + (pick.m || \"-\") + \" Num:\" + (pick.n || \"-\") + \" Ord:\" + (pick.o || \"-\");\n    }\n\n    function tryCommitCard() {\n      if (pick.n === \"Jo\" && pick.o) {\n        state.queries[cardRow] = \"Jo/\" + pick.o;\n        closeCard();\n        renderRows();\n        return;\n      }\n      if (pick.m && pick.n && pick.n !== \"Jo\" && pick.o) {\n        state.queries[cardRow] = pick.m + pick.n + \"/\" + pick.o;\n        closeCard();\n        renderRows();\n      }\n    }\n\n    function closeCard() {\n      document.getElementById(\"cardModal\").style.display = \"none\";\n      cardRow = -1;\n    }\n\n    document.getElementById(\"cardClose\").onclick = closeCard;\n    document.getElementById(\"cardClear\").onclick = () => {\n      if (cardRow >= 0) state.queries[cardRow] = \"\";\n      closeCard();\n      renderRows();\n    };\n\n    document.getElementById(\"gateBtn\").onclick = () => {\n      const v = document.getElementById(\"gateToken\").value.trim();\n      if (!v) return toast(\"トークンを入力してください\");\n      adminToken = v;\n      localStorage.setItem(LS, adminToken);\n      startApp();\n    };\n\n    document.getElementById(\"addRow\").onclick = () => {\n      state.queries.push(\"\");\n      renderRows();\n    };\n    document.getElementById(\"saveBtn\").onclick = () => save().catch((e) => toast(String(e.message || e)));\n    document.getElementById(\"resetCounter\").onclick = () =>\n      api(\"/api/reset-counter\", { method: \"POST\" })\n        .then((d) => { state = d.state; toast(\"カウンタを0にしました\"); renderAll(); })\n        .catch((e) => toast(String(e.message || e)));\n\n    document.getElementById(\"btnPerform\").onclick = () =>\n      api(\"/api/performance\", { method: \"POST\", body: JSON.stringify({ action: \"start\", permanent: false }) })\n        .then((d) => { state = d.state; toast(\"パフォーマンス開始\"); renderAll(); })\n        .catch((e) => toast(String(e.message || e)));\n\n    document.getElementById(\"btnPermanent\").onclick = () =>\n      api(\"/api/performance\", { method: \"POST\", body: JSON.stringify({ action: \"start\", permanent: true }) })\n        .then((d) => { state = d.state; toast(\"永続化パフォーマンス開始\"); renderAll(); })\n        .catch((e) => toast(String(e.message || e)));\n\n    document.getElementById(\"btnFinish\").onclick = () =>\n      api(\"/api/performance\", { method: \"POST\", body: JSON.stringify({ action: \"end\" }) })\n        .then((d) => { state = d.state; toast(\"終了しました\"); renderAll(); })\n        .catch((e) => toast(String(e.message || e)));\n\n    document.getElementById(\"btnIssueTickets\").onclick = () => {\n      const n = parseInt(document.getElementById(\"ticketCount\").value, 10);\n      if (!Number.isFinite(n) || n < 1 || n > 5000) return toast(\"枚数は1〜5000\");\n      api(\"/api/tickets/bulk\", { method: \"POST\", body: JSON.stringify({ count: n }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          const base = audienceOrigin();\n          const lines = (d.tickets || []).map((x) => base + x.path);\n          document.getElementById(\"ticketUrls\").value = lines.join(\"\\n\");\n          toast(\"発行しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n    document.getElementById(\"btnClearTickets\").onclick = () => {\n      if (!confirm(\"名刺用URLをすべて削除します。よろしいですか？\")) return;\n      api(\"/api/tickets/clear\", { method: \"POST\", body: JSON.stringify({ confirm: true }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          document.getElementById(\"ticketUrls\").value = \"\";\n          toast(\"削除しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n\n    let pollTimer = null;\n    function startPublicUrlPoller() {\n      if (pollTimer) return;\n      let n = 0;\n      pollTimer = setInterval(async () => {\n        n++;\n        if (n > 45) {\n          clearInterval(pollTimer);\n          pollTimer = null;\n        }\n        try {\n          const r = await fetch(\"/api/public-qr-hint\");\n          const d = await r.json();\n          const base = (d.publicBaseUrl || \"\").replace(/\\/+$/, \"\");\n          if (base && d.publicPath && state) {\n            const changed = base !== publicBaseUrl;\n            publicBaseUrl = base;\n            publicPath = d.publicPath;\n            if (changed) {\n              const full = audienceOrigin() + publicPath;\n              document.getElementById(\"publicUrl\").textContent = full;\n              renderQr(full);\n            }\n          }\n        } catch (_) {}\n      }, 2000);\n    }\n\n    async function startApp() {\n      try {\n        await load();\n        gate.style.display = \"none\";\n        appEl.style.display = \"block\";\n        startPublicUrlPoller();\n      } catch (e) {\n        localStorage.removeItem(LS);\n        adminToken = \"\";\n        gate.style.display = \"block\";\n        appEl.style.display = \"none\";\n        toast(\"読み込み失敗: トークンを確認してください\");\n      }\n    }\n\n    if (adminToken) startApp();\n  </script>\n</body>\n</html>\n";
